/* 3. Dialog Popup Styles */
.popup-backdrop {
  position: fixed;
  top: 0; left: 0; right: 0; bottom: 0;
  background-color: rgba(15, 23, 42, 0.4);
  backdrop-filter: blur(5px);
  z-index: 1000;
  display: flex;
  justify-content: center;
  align-items: center;
}

.popup-dialog {
  width: 85%;
  max-width: 340px;
  background-color: #ffffff;
  border-radius: 20px;
  padding: 24px;
  box-shadow: 0 20px 25px -5px rgba(0, 0, 0, 0.1);
  z-index: 1010;
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
}

.dialog-icon {
  width: 48px;
  height: 48px;
  background-color: rgba(239, 68, 68, 0.1);
  color: #ef4444;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 16px;
}

.dialog-buttons {
  display: flex;
  width: 100%;
  gap: 8px;
}

.btn-dialog {
  flex: 1;
  padding: 12px;
  font-weight: 700;
  border-radius: 10px;
  cursor: pointer;
  border: none;
}

.btn-dialog-cancel {
  background-color: #f1f5f9;
  color: #64748b;
}

.btn-dialog-danger {
  background-color: #ef4444;
  color: #ffffff;
}
